esqlQuery.esql:
FROM metrics-postgresqlreceiver.otel-*
// Include both server-level (connection.max) and database-level (backends) metrics
| WHERE postgresql.backends IS NOT NULL OR postgresql.connection.max IS NOT NULL
// Aggregate total backends and max connections per instance
| STATS total_backends = SUM(postgresql.backends), conn_max = MAX(postgresql.connection.max) BY service.instance.id
// Skip instances where we could not compute utilization
| WHERE conn_max > 0 AND total_backends IS NOT NULL
// Utilization as percentage; adjust 80.0 threshold for your environment
| EVAL utilization_pct = ROUND(total_backends / conn_max * 100.0, 2)
| WHERE utilization_pct > 80.0
